function installSdkModules(installDir: string): void {
  console.error(`Installing @earendil-works/pi-coding-agent into ${installDir} via npm...`);
  mkdirSync(installDir, { recursive: true });
  execSync('npm install --no-save --no-package-lock @earendil-works/pi-coding-agent', {
    cwd: installDir,
    stdio: 'inherit',
  });
}

async function doLoadSdkModules(): Promise<void> {
  if (
    (await tryImportLocalSdkModules()) ||
    (await tryImportManagedSdkModules()) ||
    (await tryImportGlobalSdkModules())
  ) {
    return;
  }

  if (await promptInstall()) {
    const installDir = findManagedSdkInstallRoot();
    installSdkModules(installDir);
    if (await tryImportManagedSdkModules()) {
      return;
    }
  }

  const missing = new Error(
    'pi-coding-agent SDK dependencies are not installed. AgentV declares SDK beta packages as optional dependencies; run bun install to hydrate optional dependencies, or install the Pi SDK packages explicitly:\n  bun add --optional @earendil-works/pi-coding-agent @earendil-works/pi-ai\n  npm install @earendil-works/pi-coding-agent @earendil-works/pi-ai',
  );
  missing.name = 'MissingSdkDependency';
  throw missing;
}

async function loadSdkModules() {
  if (!piCodingAgentModule || !piAiModule) {
    if (!loadingPromise) {
      loadingPromise = doLoadSdkModules().catch((err) => {
        loadingPromise = null;
        throw err;
      });
    }
    await loadingPromise;
  }
  // After doLoadSdkModules resolves, both modules are guaranteed non-null.
  const piSdk = piCodingAgentModule as NonNullable<typeof piCodingAgentModule>;
  const piAi = piAiModule as NonNullable<typeof piAiModule>;
  return {
    createAgentSession: piSdk.createAgentSession,
    SessionManager: piSdk.SessionManager,
    getModel: piAi.getModel,
    // biome-ignore lint/suspicious/noExplicitAny: registerBuiltInApiProviders exists at runtime but not in type defs
    registerBuiltInApiProviders: (piAi as any).registerBuiltInApiProviders as () => void,
  };
}

